    pub const fn is_mutating_execution_step(self) -> bool {
        !matches!(
            self,
            Self::SkipAlreadyDesired
                | Self::SkipNotFound
                | Self::SkipUnsupportedVersion
                | Self::PlanFailure
        )
    }
